//! Database setup utilities for integration testing

use rusqlite::Connection;
use tempfile::{TempDir, tempdir};

/// Create an in-memory test database with full schema
pub fn setup_test_db() -> Connection {
    let conn = Connection::open_in_memory().unwrap();
    conn.execute_batch(include_str!("../../schema.sql")).unwrap();
    conn
}

/// Create a temporary directory with a populated test database
pub fn setup_test_index(session_count: usize) -> TempDir {
    let temp_dir = tempdir().unwrap();
    let db_path = temp_dir.path().join("cass.db");

    let mut conn = Connection::open(&db_path).unwrap();
    conn.execute_batch(include_str!("../../schema.sql")).unwrap();

    // Populate with test data
    let mut rng = seeded_rng(12345);
    for i in 0..session_count {
        let meta = generate_metadata(&mut rng, i);
        insert_test_session(&conn, &meta);
    }

    temp_dir
}

/// Insert a test session into the database
pub fn insert_test_session(conn: &Connection, meta: &ConversationMetadata) {
    conn.execute(
        "INSERT INTO conversations (source_path, agent_type, timestamp, message_count, total_chars, metadata)
         VALUES (?, ?, ?, ?, ?, ?)",
        rusqlite::params![
            meta.source_path,
            meta.agent_type,
            meta.timestamp,
            meta.message_count,
            meta.total_chars,
            serde_json::to_string(meta).unwrap(),
        ],
    ).unwrap();
}

/// Setup database with specific date range of sessions
pub fn setup_test_index_with_dates(
    sessions_per_day: usize,
    num_days: usize,
    seed: u64,
) -> TempDir {
    let temp_dir = tempdir().unwrap();
    let db_path = temp_dir.path().join("cass.db");

    let mut conn = Connection::open(&db_path).unwrap();
    conn.execute_batch(include_str!("../../schema.sql")).unwrap();

    let mut rng = seeded_rng(seed);
    let base_ts = 1704067200; // 2024-01-01

    for day in 0..num_days {
        for session in 0..sessions_per_day {
