//! Custom assertions for optimization correctness testing

/// Assert that two floating point values are equal within tolerance
pub fn assert_float_eq(expected: f32, actual: f32, tolerance: f32, context: &str) {
    let diff = (expected - actual).abs();
    let relative_diff = if expected.abs() > 1e-10 {
        diff / expected.abs()
    } else {
        diff
    };

    assert!(
        relative_diff < tolerance,
        "{}: expected {}, got {}, diff {} (relative {})",
        context, expected, actual, diff, relative_diff
    );
}

/// Assert that two iterators produce the same elements (order-independent)
pub fn assert_same_elements<T, I1, I2>(expected: I1, actual: I2, context: &str)
where
    T: std::fmt::Debug + Eq + std::hash::Hash,
    I1: IntoIterator<Item = T>,
    I2: IntoIterator<Item = T>,
{
    use std::collections::HashSet;

    let expected_set: HashSet<T> = expected.into_iter().collect();
    let actual_set: HashSet<T> = actual.into_iter().collect();

    assert_eq!(
        expected_set, actual_set,
        "{}: element sets differ", context
    );
}

/// Assert that two vectors are equal element-wise within tolerance
pub fn assert_vec_float_eq(expected: &[f32], actual: &[f32], tolerance: f32, context: &str) {
    assert_eq!(
        expected.len(), actual.len(),
        "{}: length mismatch ({} vs {})", context, expected.len(), actual.len()
    );

    for (i, (e, a)) in expected.iter().zip(actual.iter()).enumerate() {
        assert_float_eq(*e, *a, tolerance, &format!("{}[{}]", context, i));
    }
}

/// Assert that an operation produces isomorphic results
/// (same inputs produce same outputs, even if implementation differs)
#[macro_export]
macro_rules! assert_isomorphic {
    ($old:expr, $new:expr, $input:expr) => {{
        let old_result = $old($input);
        let new_result = $new($input);
        assert_eq!(
            old_result, new_result,
            "Implementations not isomorphic for input: {:?}",
            $input
        );
    }};
}
